import{_ as a,o as t,c as s,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Grant an Agency Access","description":"","frontmatter":{"title":"Grant an Agency Access","slug":"grant-an-agency-access"},"headers":[],"relativePath":"account-hub/grant-an-agency-access.md","filePath":"account-hub/grant-an-agency-access.md"}'),n={name:"account-hub/grant-an-agency-access.md"};function r(c,e,i,l,g,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<p>We allow you to grant agencies access to your account. Agencies have their own <a href="./entity-views-access-controls-overview.html#agency-view">entity view</a>, which limits them to what they can see/do within the Branch dashboard. This guide will walk you through how to add agencies to your account and configure access levels. Note that the following steps also apply to granting Ad Partner access.</p><h2 id="grant-an-agency-access-to-your-account" tabindex="-1">Grant an Agency Access to Your Account <a class="header-anchor" href="#grant-an-agency-access-to-your-account" aria-label="Permalink to &quot;Grant an Agency Access to Your Account&quot;">​</a></h2><ol><li><p>Go to the <a href="https://dashboard.branch.io/account-settings/agencies" target="_blank" rel="noreferrer">Account Settings</a> page in the dashboard, and click to the <a href="https://dashboard.branch.io/account-settings/agencies" target="_blank" rel="noreferrer">Agencies</a> tab. If you do not see your agency, please ask your agency to fill out the <a href="https://branchmetrics.typeform.com/to/XXkMePO9" target="_blank" rel="noreferrer">Branch Partner Form</a>.</p></li><li><p>Click <strong>Add New Agency</strong>.</p></li><li><p>Complete the following fields:</p><ul><li><p><strong>Agency Name</strong>: Search and select the Agency you wish to add.</p></li><li><p><strong>Access Level</strong>: Select the level of access you wish to grant the agency. By default, <strong>custom</strong> will be selected. Reference <a href="./add-manage-users-roles-permissions-access.html#roles">Roles</a> to understand the various access levels.</p><ul><li>Note: You may grant an agency the access level <strong>No Access</strong>. This access level allows you to define specific agency users that can access your account. See <a href="./add-agency-to-your-account.html#faqs-on-agency-access">below</a> for further instructions on managing individual agency user permissions.</li></ul></li><li><p><strong>Permissions</strong>: While permissions are auto-populated based on the <strong>Access Level</strong> you&#39;ve chosen, you can change any of the <a href="./add-manage-users-roles-permissions-access.html#access-levels"><strong>Permissions</strong></a> as you see fit.</p></li><li><p><strong>Export</strong>: If you wish to allow the agency to export data, you will need to grant access to both Sensitive Data and Export.</p></li><li><p><strong>Data Filters</strong>: Define the data filter permissions you wish for the agency to have access to. You&#39;ll have the following options:</p><ul><li><p><strong>Only show agency-tagged data</strong>: When toggled on, agency users can only view data - i.e. events, engagement groups - tagged with their Agency ID. This will be enabled by default.</p></li><li><p><strong>Restrict access to revenue data</strong>: Agency can view revenue data if sensitive data is granted.</p></li><li><p><strong>Only show data from specific ad networks</strong>: When toggled on, agency users can only view events from a specific list of ad networks.</p><ul><li>If you selected an agency that is also an ad network, this field should auto-populate with the ad network.</li><li>LIMITATION: If the number of one specific event in the latest 7 days is zero, the event will not be shown as an option in the ADD/REMOVE COLUMNS in the EVENTS section on the dashboard.</li></ul></li><li><p><strong>Only show data from specific locations</strong>: When toggled on, agency users can only view events that have taken place in a specific list of countries.</p></li></ul></li></ul></li></ol><div class="info custom-block"><p class="custom-block-title">Data Filters for Ad Partners</p><p>If you&#39;re working with an Ad Partner in a paid advertising campaign and would like to grant dashboard access, the following Data Filters are recommended:</p><ul><li><strong>Only show agency-tagged data</strong>: Toggled off.</li><li><strong>Restrict access to revenue data</strong>: If desired.</li><li><strong>Only show data from specific ad networks</strong>: Toggled on, and select the specific ad network(s) to show data for.</li><li><strong>Only show data from specific locations</strong>: If desired.</li></ul></div><ol start="4"><li><p>When you&#39;re done, click <strong>Invite</strong>.</p><p><em>[Image: 708]</em></p></li></ol><h2 id="default-agency-access-level-restrictions" tabindex="-1">Default Agency Access Level Restrictions <a class="header-anchor" href="#default-agency-access-level-restrictions" aria-label="Permalink to &quot;Default Agency Access Level Restrictions&quot;">​</a></h2><p>Due to the nature of allowing third parties access to your data - as well as what data you don&#39;t want them to access - when an Agency team member is in App view, they will not be able to access certain aspects of the Branch account regardless of the access levels applied to the user.</p><ul><li><p>Agency users cannot add/remove team members to/from their customers’ dashboards.</p></li><li><p>Agency users are not allowed to reset app keys or delete apps.</p></li><li><p>Agency users are not allowed to add/remove agency access.</p></li><li><p>Agency users are allowed to create apps in the Organization view, but not stand-alone apps in the App view.</p><ul><li>This means agencies don’t actually “own” apps; rather they’ll just be able to manage the apps of others.</li></ul></li><li><p>Agency users do not have access to the Billing and SSO sections of their customers’ dashboards.</p></li></ul><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>How can I manage individual agency users’ access levels?</summary><p>We understand you might not want to grant all agency users access to your account, but rather grant specific agency users access with a specific permission set. To do this:</p><ol><li>When following the steps to <a href="https://help.branch.io/v1/docs/add-agency-to-your-account#grant-an-agency-access-to-your-account" target="_blank" rel="noreferrer">grant an agency access</a>, for <strong>Access Levels</strong> select *No Access.</li><li>After granting the Agency access to your account, the agency will have to accept their invite. After they accept you can continue to follow this process.</li><li>Once the agency has accepted their invite, go back to the Agency tab. Find the agency you added and click on the name of the agency.</li><li>Here you will see all of the agency users associated with that agency. Find the user you wish to grant access to your account.</li><li>In the <strong>Action</strong> column, click on the <strong>...</strong> and click <strong>Edit</strong>.</li><li>Reference our guide on <a href="https://help.branch.io/v1/docs/add-manage-users-roles-permissions-access#access-levels" target="_blank" rel="noreferrer">access levels</a> to understand the various permission sets.</li><li>Click <strong>Save</strong>.</li></ol></details><details><summary>How do I grant agencies the ability to export data?</summary><p>If you wish to allow the agency to export data, you will need to grant access to <em>both</em> <strong>Sensitive Data</strong> and <strong>Export</strong>. <a href="https://help.branch.io/v1/docs/add-agency-to-your-account" target="_blank" rel="noreferrer">See here for more information about how to manage Agency access</a>.</p></details><details><summary>Why can’t I see User Management buttons on the team management page?</summary><p>User Management is only possible from the Live App in Branch. If you are on the Test Mode you will not see User Management buttons next to the Users on your Team Management page. Switch to Live mode to make changes to Users.</p></details><details><summary>Do agency users have access to organic data?</summary><p>When you view data through an Agency Dashboard you will only be able to see the data from ad partners that have been made visible to you.</p><p>Data from other ad partners and organic data will not be available.</p></details>',13)])])}const p=a(n,[["render",r]]);export{u as __pageData,p as default};
